#include <bits/stdc++.h>
using namespace std;

const int N=1e5+5;

struct Edge{
    int to,val;
};

int n,m,d[N];
double f[N],p[N];
vector<Edge> g[N];

int main(){
    scanf("%d%d",&n,&m);
    for(int i=0,u,v,w;i<m;i++){
        scanf("%d%d%d",&u,&v,&w);
        g[u].push_back({v,w}),d[v]++;
    }
    queue<int> q;
    q.push(1);
    p[1]=1;
    while(q.size()){
        int x=q.front(),k=g[x].size();
        q.pop();
        for(Edge y:g[x]){
            f[y.to]+=(f[x]+1.0*y.val*p[x])/k;
            p[y.to]+=p[x]/k;
            if(!--d[y.to])
                q.push(y.to);
        }
    }
    printf("%.2lf",f[n]);
    return 0;
}
